135→private val PostListDiffItemCallback = object : DiffUtil.ItemCallback<PostListItemType>() {
136→    override fun areItemsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
137→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
138→            return true
139→        }
140→        if (oldItem is LoadingItem && newItem is LoadingItem) {
141→            return oldItem.localOrRemoteId == newItem.localOrRemoteId
142→        }
143→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
144→            return oldItem.data.localPostId == newItem.data.localPostId
145→        }
146→        if (oldItem is LoadingItem && newItem is PostListItemUiState) {
147→            return when (oldItem.localOrRemoteId) {
148→                is LocalId -> oldItem.localOrRemoteId == newItem.data.localPostId.id
149→                is RemoteId -> oldItem.localOrRemoteId == newItem.data.remotePostId.id
150→            }
151→        }
152→        return false
153→    }
154→
155→    override fun areContentsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
156→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
157→            return true
158→        }
159→        if (oldItem is LoadingItem && newItem is LoadingItem) {
160→            return when (oldItem.localOrRemoteId) {
161→                is LocalId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? LocalId)?.value
162→                is RemoteId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? RemoteId)?.value
163→            }
164→        }
165→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
166→            return oldItem.data == newItem.data
167→        }
168→        return false
169→    }
